  ZoneCache,
  HttpProblems,
  environment,
  InboundPolicyHandler,
} from "@zuplo/runtime";

interface CircuitBreakerState {
  consecutiveFailures: number;
  isOpen: boolean;
}

interface CircuitBreakerInboundOptions {
  failureThreshold: number;
}

const CACHE_NAME = "circuit-breaker-state";
const CACHE_TTL_SECONDS = 600; // 10 minutes

export const circuitBreakerInboundPolicy: InboundPolicyHandler<CircuitBreakerInboundOptions> =
  async (request: ZuploRequest, context: ZuploContext, options, policyName) => {
    const runId = environment.ZEALT_RUN_ID || "default";
    const cacheKey = `circuit-state-${runId}`;

    const cache = new ZoneCache<CircuitBreakerState>(CACHE_NAME, context);
    const state = await cache.get(cacheKey);

    if (state && state.isOpen) {
      context.log.info(
        `Circuit breaker is OPEN. Rejecting request immediately. (consecutiveFailures: ${state.consecutiveFailures})`
      );
      return HttpProblems.serviceUnavailable(request, context, {
        detail: "Service unavailable - circuit breaker is open due to consecutive backend failures.",
      });
    }

    return request;
  };

import {
  ZuploRequest,
  ZuploContext,
  ZoneCache,
  environment,
  OutboundPolicyHandler,
} from "@zuplo/runtime";

interface CircuitBreakerState {
  consecutiveFailures: number;
  isOpen: boolean;
}

interface CircuitBreakerOutboundOptions {
  failureThreshold: number;
}

const CACHE_NAME = "circuit-breaker-state";
const CACHE_TTL_SECONDS = 600; // 10 minutes

export const circuitBreakerOutboundPolicy: OutboundPolicyHandler<CircuitBreakerOutboundOptions> =
  async (
    response: Response,
    request: ZuploRequest,
    context: ZuploContext,
    options,
    policyName
  ) => {
    const runId = environment.ZEALT_RUN_ID || "default";
    const cacheKey = `circuit-state-${runId}`;
    const failureThreshold = options.failureThreshold || 5;

    const cache = new ZoneCache<CircuitBreakerState>(CACHE_NAME, context);
    let state = await cache.get(cacheKey);

    if (!state) {
      state = { consecutiveFailures: 0, isOpen: false };
    }

    if (response.status >= 500 && response.status < 600) {
      // Backend returned a 5xx - increment failure count
      state.consecutiveFailures += 1;
      context.log.info(
        `Circuit breaker: backend returned ${response.status}. Consecutive failures: ${state.consecutiveFailures}/${failureThreshold}`
      );

      if (state.consecutiveFailures >= failureThreshold) {
        state.isOpen = true;
        context.log.warn(
          `Circuit breaker TRIPPED! Consecutive failures reached threshold of ${failureThreshold}. Circuit is now OPEN.`
        );
      }

      await cache.put(cacheKey, state, CACHE_TTL_SECONDS);
    } else {
      // Backend returned a successful response - reset failure count
      if (state.consecutiveFailures > 0) {
        context.log.info(
          `Circuit breaker: backend recovered with status ${response.status}. Resetting consecutive failures from ${state.consecutiveFailures} to 0.`
        );
      }
      state.consecutiveFailures = 0;
      state.isOpen = false;
      await cache.put(cacheKey, state, CACHE_TTL_SECONDS);
    }

    return response;
  };

